#nullable enable // autogenerated

using MVZ2.GameContent.Buffs.Enemies;
using MVZ2.GameContent.Detections;
using MVZ2.Vanilla.Audios;
using MVZ2.Vanilla.Detections;
using MVZ2.Vanilla.Entities;
using MVZ2.Vanilla.Projectiles;
using MVZ2.Vanilla.Properties;
using MVZ2Logic.Entities;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Buffs;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using Tools;

namespace MVZ2.GameContent.Enemies
{
    [AutoEntityBehaviourDefinition(VanillaEnemyNames.JollyRogerZombie)]
    public class JollyRogerZombie : PirateZombie
    {
        public JollyRogerZombie(string nsp, string name) : base(nsp, name)
        {
            detector = new DispenserDetector()
            {
                ignoreHighEnemy = true,
                ignoreLowEnemy = true
            };
        }

        public override void Init(Entity entity)
        {
            base.Init(entity);
            entity.SetModelProperty("HasFlag", true);
            var speedBuff = entity.GetFirstBuff<RandomEnemySpeedBuff>();
            if (speedBuff != null)
            {
                RandomEnemySpeedBuff.SetSpeed(speedBuff, 2);
            }
        }

        protected override void UpdateAI(Entity enemy)
        {
            base.UpdateAI(enemy);

            // 每帧推进 reload 计时器  
            var reloadTimer = GetReloadTimer(enemy);
            if (reloadTimer != null)
            {
                reloadTimer.Run(enemy.GetAttackSpeed());
                if (reloadTimer.Expired)
                {
                    SetIsReloading(enemy, false);
                }
            }

            // 检查是否还有子弹  
            if (GetAmmo(enemy) > 0)
            {
                if (CanShoot(enemy))
                {
                    if (enemy.Target != null && !ValidateTarget(enemy, enemy.Target))
                    {
                        enemy.Target = null;
                    }
                    enemy.Target = FindTarget(enemy);
                }
                else
                {
                    enemy.Target = null;
                }

                // 远程攻击状态下尝试开火  
                if (enemy.State == STATE_RANGED_ATTACK && enemy.Target != null)
                {
                    if (!GetIsReloading(enemy))
                    {
                        // 消耗一发子弹  
                        int currentAmmo = GetAmmo(enemy);
                        currentAmmo--;
                        SetAmmo(enemy, currentAmmo);

                        // 发射子弹  
                        enemy.ShootProjectile();
                        enemy.PlaySound(VanillaSoundID.gunShot);

                        // 进入 reload  
                        SetIsReloading(enemy, true);
                        SetReloadTimer(enemy, new FrameTimer(RELOAD_TIME));
                    }
                }
            }
            else
            {
                // 子弹用完，转为近战攻击  
                enemy.Target = null;
            }
        }

        private bool CanShoot(Entity enemy)
        {
            return enemy.Position.x <= enemy.Level.GetEntityColumnX(enemy.Level.GetMaxColumnCount() - 1);
        }

        private Entity? FindTarget(Entity entity)
        {
            var collider = detector.Detect(entity);
            return collider?.Entity;
        }

        private bool ValidateTarget(Entity entity, Entity target)
        {
            return detector.ValidateTarget(entity, target);
        }


        // 获取和设置子弹数量
        public static int GetAmmo(Entity enemy) => enemy.GetBehaviourField<int>(ID, PROP_AMMO) is int ammo ? ammo : MAX_AMMO;
        public static void SetAmmo(Entity enemy, int value) => enemy.SetBehaviourField(ID, PROP_AMMO, value);

        // 获取和设置 reload 状态
        public static bool GetIsReloading(Entity enemy) => enemy.GetBehaviourField<bool>(ID, PROP_IS_RELOADING);
        public static void SetIsReloading(Entity enemy, bool value) => enemy.SetBehaviourField(ID, PROP_IS_RELOADING, value);

        // 获取和设置 reload 计时器
        public static FrameTimer? GetReloadTimer(Entity enemy) => enemy.GetBehaviourField<FrameTimer>(ID, PROP_RELOAD_TIMER);
        public static void SetReloadTimer(Entity enemy, FrameTimer value) => enemy.SetBehaviourField(ID, PROP_RELOAD_TIMER, value);

        private Detector detector;
        private static readonly NamespaceID ID = VanillaEnemyID.MusketeerZombie;
        public static readonly VanillaEntityPropertyMeta<int> PROP_AMMO = new VanillaEntityPropertyMeta<int>("ammo", MAX_AMMO);
        public static readonly VanillaEntityPropertyMeta<bool> PROP_IS_RELOADING = new VanillaEntityPropertyMeta<bool>("isReloading", false);
        public static readonly VanillaEntityPropertyMeta<FrameTimer> PROP_RELOAD_TIMER = new VanillaEntityPropertyMeta<FrameTimer>("reloadTimer");
        public const int STATE_WALK = LogicEnemyStates.WALK;
        public const int STATE_RANGED_ATTACK = LogicEnemyStates.RANGED_ATTACK;
        public const int MAX_AMMO = 3;
        public const int RELOAD_TIME = 90;
    }
}
